#include <variant>
#include <string>
#include <iostream>

using Msg = std::variant<int, std::string>;
void process(Msg m) {
    std::visit([](auto&& arg) {
        using T = std::decay_t<decltype(arg)>;
        if constexpr (std::is_same_v<T, int>) std::cout << "Int: " << arg;
        else if constexpr (std::is_same_v<T, std::string>) std::cout << "Str: " << arg;
    }, m);
}

#include <vector>
#include <algorithm>

std::vector<int> square(const std::vector<int>& source) {
    std::vector<int> dest;
    dest.reserve(source.size());
    for(int x : source) dest.push_back(x * x);
    return dest;
}
